# ## 🔥 Extension Tasks

# ### Extension A — Rate-Limiting Middleware *(Medium)*
# Add a sliding-window rate limiter (e.g., 100 req/min per client IP) using an in-memory dictionary.
# - Return `429 Too Many Requests` with a `Retry-After` header when the limit is exceeded
# - Track limit hits as a Prometheus `Counter`

from collections import defaultdict, deque
from prometheus_client import Counter

RATE_LIMIT_HITS = Counter(
    "rate_limit_hits_total",
    "Total rate limit violations"
)

from time import time

RATE_LIMIT = 100          # requests
WINDOW_SECONDS = 60       # per minute

request_store = defaultdict(deque)

from fastapi.responses import JSONResponse

@app.middleware("http")
async def rate_limit_middleware(request: Request, call_next):

    client_ip = request.client.host
    now = time()

    bucket = request_store[client_ip]

    # Remove expired timestamps
    while bucket and bucket[0] < now - WINDOW_SECONDS:
        bucket.popleft()

    if len(bucket) >= RATE_LIMIT:
        RATE_LIMIT_HITS.inc()

        retry_after = int(WINDOW_SECONDS - (now - bucket[0]))

        return JSONResponse(
            status_code=429,
            content={"detail": "Rate limit exceeded"},
            headers={"Retry-After": str(retry_after)}
        )

    bucket.append(now)

    return await call_next(request)

# ### Extension B — Correlation ID Propagation *(Medium)*
# The current middleware assigns a correlation ID but does NOT forward it to outbound `httpx` calls.
# - Add a `contextvars.ContextVar` to store the correlation ID per request
# - Write a custom `httpx.Auth` or event hook that injects `X-Correlation-Id` into every outbound call
# - Verify it appears in mock downstream requests

# ===================================
# EXTENSION B
# Correlation ID Propagation
# ===================================

import contextvars
import httpx
import uuid
from fastapi import Request

# Store correlation ID per request
correlation_id_ctx = contextvars.ContextVar(
    "correlation_id",
    default=None
)

# Replace previous middleware with this version
@app.middleware("http")
async def correlation_logging_middleware(
    request: Request,
    call_next
):
    correlation_id = request.headers.get(
        "X-Correlation-Id",
        str(uuid.uuid4())
    )

    correlation_id_ctx.set(correlation_id)

    response = await call_next(request)

    response.headers["X-Correlation-Id"] = correlation_id
    return response


# Inject correlation ID into every outbound request
async def add_correlation_id(request: httpx.Request):
    cid = correlation_id_ctx.get()

    if cid:
        request.headers["X-Correlation-Id"] = cid


http_client = httpx.AsyncClient(
    event_hooks={
        "request": [add_correlation_id]
    }
)

# Demo endpoint
@app.get("/propagation-test")
async def propagation_test():

    response = await http_client.get(
        "https://httpbin.org/headers"
    )

    return response.json()

print("✅ Correlation ID propagation enabled")
print("   Test endpoint: /propagation-test")

