# - Write a query that finds all requests with `latency_ms > 200` for a specific `correlation_id`



# ===================================
# EXTENSION D
# Structured Log Aggregation
# ===================================

import json

# Create sample NDJSON log file
sample_logs = [
    {
        "event": "request.completed",
        "correlation_id": "abc123",
        "latency_ms": 312,
        "status": 200
    },
    {
        "event": "request.completed",
        "correlation_id": "xyz789",
        "latency_ms": 80,
        "status": 200
    },
    {
        "event": "request.completed",
        "correlation_id": "abc123",
        "latency_ms": 450,
        "status": 500
    }
]

with open("payments.ndjson", "w") as f:
    for log in sample_logs:
        f.write(json.dumps(log) + "\n")

print("✅ payments.ndjson created")

# Query logs
print("\n🔍 Slow requests (>200ms) for correlation_id='abc123'\n")

with open("payments.ndjson", "r") as f:
    for line in f:
        record = json.loads(line)

        if (
            record.get("correlation_id") == "abc123"
            and record.get("latency_ms", 0) > 200
        ):
            print(record)

print("\n✅ Log aggregation demo completed")

